package com.enterprise.auth.service;

import com.enterprise.auth.model.User;
import com.enterprise.auth.model.BackupCode;
import com.enterprise.auth.repository.BackupCodeRepository;
import com.enterprise.auth.repository.UserRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.stream.Collectors;

@Service
@Transactional
public class BackupCodeService {

    private static final int CODE_LENGTH = 8;
    private static final int CODE_COUNT = 10;

    @Autowired
    private BackupCodeRepository backupCodeRepository;

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private SecureRandom secureRandom;

    public List<String> generateBackupCodes(Long userId) {
        List<String> codes = new ArrayList<>();
        for (int i = 0; i < CODE_COUNT; i++) {
            codes.add(generateUniqueCode());
        }
        
        // Delete existing backup codes for user
        backupCodeRepository.deleteByUserId(userId);
        
        // Save new backup codes
        List<BackupCode> backupCodeEntities = codes.stream()
            .map(code -> {
                BackupCode backupCode = new BackupCode();
                backupCode.setUserId(userId);
                backupCode.setCode(code);
                backupCode.setUsed(false);
                backupCode.setCreatedAt(LocalDateTime.now());
                return backupCode;
            })
            .collect(Collectors.toList());
            
        backupCodeRepository.saveAll(backupCodeEntities);
        
        return codes;
    }

    private String generateUniqueCode() {
        StringBuilder code = new StringBuilder();
        for (int i = 0; i < CODE_LENGTH; i++) {
            code.append(secureRandom.nextInt(10));
        }
        return code.toString();
    }

    public boolean validateBackupCode(Long userId, String code) {
        BackupCode backupCode = backupCodeRepository.findByUserIdAndCode(userId, code);
        if (backupCode != null && !backupCode.isUsed()) {
            backupCode.setUsed(true);
            backupCode.setUsedAt(LocalDateTime.now());
            backupCodeRepository.save(backupCode);
            return true;
        }
        return false;
    }

    public boolean isBackupCodeUsed(Long userId, String code) {
        BackupCode backupCode = backupCodeRepository.findByUserIdAndCode(userId, code);
        return backupCode != null && backupCode.isUsed();
    }

    public void disableBackupCodes(Long userId) {
        backupCodeRepository.deleteByUserId(userId);
    }

    public boolean hasActiveBackupCodes(Long userId) {
        return backupCodeRepository.existsByUserIdAndUsedFalse(userId);
    }
}